  `email` varchar(255) NOT NULL,
  `password` varchar(255) NOT NULL,
  `has_started` tinyint(1) DEFAULT '0',
  `has_completed` tinyint(1) DEFAULT '0',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`email`)
